import{_ as l,C as o,o as a,c as n,a3 as e,b as r,w as i,a as p,E as c,a4 as h}from"./chunks/framework.C49Ar5GK.js";const m=JSON.parse('{"title":"性能采集：先定位等待，再打开 profiler","description":"从阶段计时、有效 token 吞吐到 PyTorch/Nsight/显存 trace，为 veRL 优化建立可比较证据","frontmatter":{"title":"性能采集：先定位等待，再打开 profiler","description":"从阶段计时、有效 token 吞吐到 PyTorch/Nsight/显存 trace，为 veRL 优化建立可比较证据","lesson":{"stage":"05 · 改造","order":23,"time":"45–70 分钟","level":"进阶实战","question":"怎样证明瓶颈属于 rollout、训练、数据、通信还是同步，而不是凭 GPU 利用率猜？"}},"headers":[],"relativePath":"practice/profiling.md","filePath":"practice/profiling.md","lastUpdated":null}'),d={name:"practice/profiling.md"};function k(g,s,u,F,_,C){const t=o("Mermaid");return a(),n("div",null,[s[1]||(s[1]=e('<h1 id="性能采集-先定位等待-再打开-profiler" tabindex="-1">性能采集：先定位等待，再打开 profiler <a class="header-anchor" href="#性能采集-先定位等待-再打开-profiler" aria-label="Permalink to &quot;性能采集：先定位等待，再打开 profiler&quot;">​</a></h1><p>性能分析的目标是回答具体问题，例如“step 慢在生成还是训练”“rollout 长尾来自排队还是 decode”“显存峰值发生在哪个 role”。一上来抓所有 rank、所有 step、所有 stack，通常只会制造巨大 trace。</p><h2 id="先用人话-优化的是一段等待-不是一个参数" tabindex="-1">先用人话：优化的是一段等待，不是一个参数 <a class="header-anchor" href="#先用人话-优化的是一段等待-不是一个参数" aria-label="Permalink to &quot;先用人话：优化的是一段等待，不是一个参数&quot;">​</a></h2><p>GPU 利用率低只是现象。它可能在等数据、最后一条长回答、权重同步、collective、CPU tokenizer，或被显存限制成很小的 batch。先把一步训练分段，找最大且可重复的等待，再用 profiler 放大那一段。</p><h2 id="证据阶梯" tabindex="-1">证据阶梯 <a class="header-anchor" href="#证据阶梯" aria-label="Permalink to &quot;证据阶梯&quot;">​</a></h2>',5)),(a(),r(h,null,{default:i(()=>[c(t,{id:"mermaid-15",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E5%9B%BA%E5%AE%9A%20commit%20%2F%20config%20%2F%20data%20slice%5D%20--%3E%20B%5B%E9%98%B6%E6%AE%B5%20timing%20%2B%20%E5%90%9E%E5%90%90%20%2B%20%E9%95%BF%E5%BA%A6%E5%88%86%E5%B8%83%5D%0A%20%20%20%20B%20--%3E%20C%7B%E7%93%B6%E9%A2%88%E5%9C%A8%E5%93%AA%E4%B8%AA%E9%98%B6%E6%AE%B5%3F%7D%0A%20%20%20%20C%20--%20rollout%20--%3E%20D%5Bserver%20metrics%20%2F%20token%20latency%20%2F%20queue%5D%0A%20%20%20%20C%20--%20actor%2Fcritic%20--%3E%20E%5BMFU%20%2F%20memory%20%2F%20mini-batch%20timing%5D%0A%20%20%20%20C%20--%20data%2FTQ%20--%3E%20F%5Bqueue%20status%20%2F%20storage%20%2F%20network%5D%0A%20%20%20%20D%20--%3E%20G%5B%E9%80%89%E4%B8%80%E4%B8%AA%20step%20%2B%20%E4%B8%80%E4%B8%AA%20replica%2Frank%20%E6%8A%93%20trace%5D%0A%20%20%20%20E%20--%3E%20G%0A%20%20%20%20F%20--%3E%20G%0A%20%20%20%20G%20--%3E%20H%5B%E6%8F%90%E5%87%BA%E6%94%B9%E5%8A%A8%E5%B9%B6%E5%81%9A%E5%90%8C%E6%9D%A1%E4%BB%B6%20A%2FB%5D%0A"})]),fallback:i(()=>[...s[0]||(s[0]=[p(" Loading... ",-1)])]),_:1})),s[2]||(s[2]=e(`<p>短跑可用于发现数量级问题，但缓存预热、编译、首轮权重同步和数据长度波动会让一两个 step 很嘈杂。比较改动时使用相同 step 区间、相同样本/seed、相同集群占用，并报告中位数与尾部。</p><h2 id="第一层-已有日志" tabindex="-1">第一层：已有日志 <a class="header-anchor" href="#第一层-已有日志" aria-label="Permalink to &quot;第一层：已有日志&quot;">​</a></h2><p><code>PPOTrainer.fit()</code> 已给 <code>gen</code>、<code>reward</code>、<code>old_log_prob</code>、<code>ref</code>、<code>values</code>、<code>adv</code>、<code>update_critic</code>、<code>update_actor</code>、<code>update_weights</code>、checkpoint/validation 等阶段计时。结合：</p><ul><li>reward/score、advantage、actor/critic loss、entropy、KL、clip fraction；</li><li>prompt/response 长度分布与有效 token 数；</li><li>actor/critic MFU、吞吐与显存；</li><li>rollout-vs-actor log-prob 差异；</li><li>off-policy dropped/staleness、版本跨度；</li><li>sequence balance 和 MoE load balance（适用时）。</li></ul><p>只看 <code>step_time</code> 无法决定优化对象。把时间换算成有效 response tokens/s，并同时记录长度分布，才能区分“系统退化”与“这批样本更长”。</p><h2 id="第二层-pytorch-profiler" tabindex="-1">第二层：PyTorch Profiler <a class="header-anchor" href="#第二层-pytorch-profiler" aria-label="Permalink to &quot;第二层：PyTorch Profiler&quot;">​</a></h2><p>先只抓 actor rank 0 的一个非首轮 step：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> verl.trainer.main_ppo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  global_profiler.tool=torch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  global_profiler.steps=&#39;[2]&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  global_profiler.save_path=outputs/profile</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  actor_rollout_ref.actor.profiler.enable=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  actor_rollout_ref.actor.profiler.all_ranks=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  actor_rollout_ref.actor.profiler.ranks=&#39;[0]&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  actor_rollout_ref.actor.profiler.tool_config.torch.contents=&#39;[cpu,cuda,memory,shapes]&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  ...</span></span></code></pre></div><p>需要 rollout 的 AgentLoop trace 时，当前官方文档要求 discrete mode：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">global_profiler.tool</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=torch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">global_profiler.steps=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;[2]&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">actor_rollout_ref.rollout.profiler.enable=true </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">actor_rollout_ref.rollout.profiler.ranks=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;[0]&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">actor_rollout_ref.rollout.profiler.tool_config.torch.discrete=true</span></span></code></pre></div><p>rollout 的 <code>ranks</code> 指 replica rank，不是训练 global rank。可用 <code>profile_token_start/end</code> 限定 decode token 窗口。trace 通常是 JSON/JSON.GZ，可用 Perfetto 或 Chrome tracing 查看。</p><p><code>stack</code> 和 <code>shapes</code> 会显著增加开销与文件体积；先用 CPU/CUDA timeline，只有需要定位算子调用点时再开。</p><h2 id="第三层-nsight-systems-nvidia" tabindex="-1">第三层：Nsight Systems（NVIDIA） <a class="header-anchor" href="#第三层-nsight-systems-nvidia" aria-label="Permalink to &quot;第三层：Nsight Systems（NVIDIA）&quot;">​</a></h2><p>根配置已给 controller/worker 的 nsys options。最小 override：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> verl.trainer.main_ppo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  global_profiler.tool=nsys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  global_profiler.steps=&#39;[2]&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  global_profiler.profile_continuous_steps=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  actor_rollout_ref.actor.profiler.enable=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  actor_rollout_ref.actor.profiler.ranks=&#39;[0]&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  ...</span></span></code></pre></div><p>代码会检查 NVTX 可用性，并把 controller 选项传给 Ray TaskRunner、worker 选项传给 WorkerGroup。不要改 worker 的 <code>capture-range=cudaProfilerApi</code>；它是 veRL 控制 start/stop 的契约。</p><p>Ray 启动的 nsys 报告默认位于每个节点 <code>/tmp/ray/session_latest/logs/nsight/</code>。多机结束后按 hostname/PID/rank 收集，避免各节点同名覆盖。重点看 CUDA kernel 空洞、CPU-GPU sync、collective、memcpy、NVTX 阶段与跨进程时间对齐。</p><h2 id="npu、显存与精度工具" tabindex="-1">NPU、显存与精度工具 <a class="header-anchor" href="#npu、显存与精度工具" aria-label="Permalink to &quot;NPU、显存与精度工具&quot;">​</a></h2><p><code>global_profiler.tool</code> 当前还接受 <code>npu</code>、<code>torch_memory</code>、<code>precision_debugger</code>：</p><ul><li><strong>npu</strong>：在 role 的 <code>tool_config.npu.contents</code> 选择 npu/cpu/memory/shapes/module/stack，并选择采集 level；</li><li><strong>torch_memory</strong>：记录 allocation/state 与 Python/C++ stack，适合定位峰值和泄漏，但 <code>trace_alloc_max_entries</code> 会影响内存开销；</li><li><strong>precision_debugger</strong>：指定 <code>actor_update</code>、<code>actor_compute_log_prob</code>、<code>ref_compute_log_prob</code>、<code>compute_values</code>、<code>critic_update</code>、<code>compute_rm_score</code> 等阶段，依赖相应工具环境。</li></ul><p>只在已复现问题的短窗口启用。profile run 的吞吐不能直接当作未采集时的性能数字。</p><h2 id="rollout-在线观测" tabindex="-1">Rollout 在线观测 <a class="header-anchor" href="#rollout-在线观测" aria-label="Permalink to &quot;Rollout 在线观测&quot;">​</a></h2><p>异步 rollout 可以让 vLLM/SGLang 暴露 Prometheus metrics，再接 Ray/Prometheus/Grafana。常见开关包括 rollout async mode、<code>disable_log_stats=false</code> 与 <code>prometheus.enable=true</code>。先直接访问每个 server 的 <code>/metrics</code> 验证采集，再排查 Prometheus discovery 和 dashboard。</p><p>关注 arrival rate、running/waiting requests、prompt/decode token throughput、KV cache utilization、time-to-first-token 和 inter-token latency。平均吞吐不错但 p99 长尾很高时，trainer 仍可能在等最后一组完整 prompt。</p><h2 id="a-b-结论模板" tabindex="-1">A/B 结论模板 <a class="header-anchor" href="#a-b-结论模板" aria-label="Permalink to &quot;A/B 结论模板&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hypothesis: rollout TP 过大导致单副本吞吐下降</span></span>
<span class="line"><span>constant: commit/config/data/seed/nodes/GPU type/step 10-30</span></span>
<span class="line"><span>change: tensor_model_parallel_size 2 -&gt; 1</span></span>
<span class="line"><span>primary: valid response tokens/s</span></span>
<span class="line"><span>guardrails: reward, response length, OOM, staleness, p95 step time</span></span>
<span class="line"><span>evidence: resolved configs + logs + selected trace</span></span>
<span class="line"><span>result: ...</span></span></code></pre></div><p>只改一个主要变量。若必须联动 batch 才能运行，把联动项也写入结论，避免把复合变化归因给一个参数。</p><h2 id="通关检查" tabindex="-1">通关检查 <a class="header-anchor" href="#通关检查" aria-label="Permalink to &quot;通关检查&quot;">​</a></h2><p>一项性能结论必须同时有：固定 workload、预热后区间、阶段 timing、有效 token 吞吐、p50/p95、算法 guardrail、改动前后 resolved config。profile trace 只负责解释机制，不能替代无 profiler 开销下的最终 A/B 数字。</p><p>课程主线到此结束，可回到<a href="/losh_has_blog/verl-learning/customization/optimization-playbook">优化方法论</a>选择下一项实验。</p>`,30))])}const f=l(d,[["render",k]]);export{m as __pageData,f as default};
